SELECT pb.id AS batch_id, pb.payment_batch_no AS batch_no, pb.pay_cycle_id AS pay_cycle_id, pb.period_label AS period_label, pb.type AS payroll_type, pb.currency AS currency, pb.status AS status, pb.remark AS remark, pb.create_time AS created_at, pb.update_time AS updated_at, COALESCE(summary.employee_count, 0) AS total_employees, COALESCE(summary.line_count, 0) AS total_lines, COALESCE(summary.gross_total, 0) AS gross_total, COALESCE(summary.net_total, 0) AS net_total, COALESCE(warning_summary.warnings, '[]') AS warnings FROM payroll_batch pb LEFT JOIN ( SELECT batch_id, COUNT(DISTINCT employee_id) AS employee_count, COUNT(*) AS line_count, COALESCE(SUM(gross_amount), 0) AS gross_total, COALESCE(SUM(net_amount), 0) AS net_total FROM payroll_line pl WHERE pl.deleted = 0 GROUP BY batch_id ) summary ON pb.id = summary.batch_id LEFT JOIN ( SELECT batch_id, CONCAT('[', GROUP_CONCAT(DISTINCT CONCAT('"', REPLACE(pl.warning, '"', '\\"'), '"') SEPARATOR ','), ']') AS warnings FROM payroll_line pl WHERE pl.deleted = 0 AND pl.warning IS NOT NULL AND pl.warning != '' GROUP BY batch_id ) warning_summary ON pb.id = warning_summary.batch_id WHERE pb.deleted = 0
AND pb.type = #{type}
AND pb.period_label = #{periodLabel}
AND pb.status = #{status}
ORDER BY pb.update_time DESC LIMIT #{offset}, #{size}

SELECT COUNT(*)
FROM payroll_batch pb
WHERE pb.deleted = 0

    AND pb.type = #{type}


    AND pb.period_label = #{periodLabel}


    AND pb.status = #{status}
